parameters.jsCode:
// OCR Gate — Combine
// The 'Merge' node in Mehta_Och AI is configured in append mode, so it emits
// TWO items: the WhatsApp payload (has .messages) and the Google Sheet row
// (has .row_number / .mode). This node does the same combine the Route code
// does, and emits a SINGLE item so the HTTP Request below fires exactly once
// per inbound WhatsApp message.

const items = $input.all();
const waItem    = items.find(it => it && it.json && it.json.messages);
const sheetItem = items.find(it => it && it.json && (it.json.row_number !== undefined || it.json.mode !== undefined));

const wa    = (waItem && waItem.json) || {};
const sheet = (sheetItem && sheetItem.json) || {};

// Prefer sheet values only when they exist (don't clobber WA data with undefined).
const combined = { ...wa, ...sheet };

// Normalise the mode field we hand the OCR service. We keep it as null if the
// user has no persisted mode yet — the service treats that as 'start a new
// OCR conversation with the default resume mode'.
if (!combined.mode || typeof combined.mode !== 'string') combined.mode = null;

return [{ json: combined }];

