parameters.jsCode:
// OCR Gate — Apply Response
// Inputs (from HTTP Request): index 0 = OCR service response JSON.
// Upstream: the combined payload we want to forward to Route when not gated.
//
// Behaviour:
//   handled=false              -> pass the combined payload through to Route.
//   handled=true, done=false   -> emit nothing (stop this run;
//                                 OCR already replied on WhatsApp).
//   handled=true, done=true    -> rewrite messages[0] as plain text with
//                                 injected_text and set mode to resume_mode,
//                                 then continue to Route exactly like a
//                                 normal user text message.

const gateItems = $input.all();
const gate = (gateItems[0] && gateItems[0].json) || {};

// Get the combined payload produced by 'OCR Gate — Combine'.
let combinedItems = [];
try { combinedItems = $items('OCR Gate — Combine'); } catch (_) { combinedItems = []; }
const combined = (combinedItems[0] && combinedItems[0].json) || {};

// 1) Not handled -> pass the combined payload through.
if (!gate || gate.handled !== true) {
  return [{ json: combined }];
}

// 2) Handled but not done -> stop.
if (gate.done !== true) {
  return [];
}

// 3) Handled and done -> inject the confirmed list as a user text message.
const injected = String(gate.injected_text || '').trim();
if (!injected) {
  return [{ json: combined }];
}

const cloned = JSON.parse(JSON.stringify(combined || {}));
cloned.messages = Array.isArray(cloned.messages) ? cloned.messages : [];
const msg = cloned.messages[0] || {};
msg.type = 'text';
msg.text = { body: injected };
delete msg.image;
delete msg.audio;
delete msg.voice;
delete msg.interactive;
delete msg.button;
cloned.messages[0] = msg;

// Carry back the mode the user was in so Route's 'continue in mode' branch
// fires (order / service / appointment / call_agent).
if (gate.resume_mode) cloned.mode = gate.resume_mode;

cloned._ocr = {
  injected: true,
  resume_mode: gate.resume_mode || null,
  at: new Date().toISOString()
};

return [{ json: cloned }];
